const n="http://localhost:9000";async function a(t,r,e=2){for(let o=0;o<=e;o++)try{return await fetch(t,r)}catch(f){if(o===e)throw f;await new Promise(s=>setTimeout(s,500))}throw new Error("unreachable")}async function c(t){try{return(await a(`${n}/${t}`,{method:"HEAD"})).ok}catch{return!1}}async function u(t){const r=await a(`${n}/${t}`,{method:"GET"});if(!r.ok)throw new Error(`文件不存在: ${t}`);const e=await r.arrayBuffer();return Buffer.from(e).toString("utf-8")}async function i(t){const r=await a(`${n}/${t}`,{method:"GET"});if(!r.ok)throw new Error(`文件不存在: ${t}`);const e=await r.arrayBuffer();return Buffer.from(e)}async function w(t,r){const e=Buffer.from(r,"utf-8"),o=await fetch(`${n}/${t}`,{method:"PUT",headers:{"Content-Type":"text/markdown; charset=utf-8"},body:e});if(!o.ok)throw new Error(`上传失败: HTTP ${o.status}`)}async function h(t,r,e="text/markdown; charset=utf-8"){const o=await fetch(`${n}/${t}`,{method:"PUT",headers:{"Content-Type":e},body:new Uint8Array(r)});if(!o.ok)throw new Error(`上传失败: HTTP ${o.status}`)}export{i as downloadBuffer,u as downloadTextFile,c as fileExists,h as uploadBuffer,w as uploadTextFile};
